import React from "react";
import axios from "axios";

function Menu(){

 const order=(food)=>{
  axios.post("http://localhost:8080/orders",{foodName:food})
  .then(()=>alert("Order Placed"));
 }

 return(
  <div className="mt-4">
   <h3>Menu</h3>
   <button className="btn btn-primary m-2" onClick={()=>order("Burger")}>Burger</button>
   <button className="btn btn-primary m-2" onClick={()=>order("Pizza")}>Pizza</button>
   <button className="btn btn-primary m-2" onClick={()=>order("Sandwich")}>Sandwich</button>
  </div>
 );
}

export default Menu;
